    function countValidSubstrings() {
        const n = s.length;
        let count = 0;
        for (let i = 0; i < n; i++) {
            if (replacePositions.has(i)) {
                // If current character is '*', add all substrings starting at i
                count += n - i;
            } else {
                // If current character is not '*', find the previous '*' position
                let prev = -1;
                for (let j = i; j < n; j++) {
                    if (replacePositions.has(j)) {
                        prev = j;
                        break;
                    }
