            }
        }
        return count;
    }

    // Check if the string is already active
    if (countValidSubstrings() >= k) {
        return -1;
    }

    // Try each time step
    for (let t = 0; t < n; t++) {
        const pos = order[t];
        replacePositions.add(pos);
        totalValidSubstrings = countValidSubstrings();
        if (totalValidSubstrings >= k) {
            return t;
        }
    }

    return -1;
}

